//! First-class cache-key teleport admission.
//!
//! The single primitive every runtime calls (fat-station, monster, moonshine,
//! gnosis-uring): validate a protocol69 cache-key projection envelope
//! (broadcast symbol 66 XOR local FOIL operand 7 = 69), and on success replay a
//! frozen amplituhedron volume LOCALLY -- a `geodesicLength:0` cached compute
//! that never traverses compute space. The key teleports; the compute does not.
//!
//! Fail-closed: a drifted projection is denied (no replay). A valid projection
//! with no frozen volume is a miss (caller runs the heavy path).

use crate::amplituhedron::AmplituhedronCache;
use crate::protocol69::{validate_protocol69_projection_envelope, Protocol69ProjectionEnvelope};

/// A teleported cache replay never traverses compute space.
pub const TELEPORT_GEODESIC_LENGTH: u32 = 0;

/// Structured outcome of a teleport admission.
#[derive(Debug)]
pub struct TeleportAdmission {
    /// protocol69 projection validated (66 XOR 7 = 69).
    pub protocol69_valid: bool,
    /// A frozen amplituhedron volume matched the admitted key.
    pub cache_hit: bool,
    /// Always 0 on this path: a cache replay does not traverse compute space.
    pub geodesic_length: u32,
    /// (tail_residual, kv_slab) on a hit.
    pub hit_payload: Option<(Vec<f32>, Vec<f32>)>,
    /// Reason the projection was denied, if invalid.
    pub denial_reason: Option<String>,
}

/// Ergonomic three-way verdict for call sites that branch on hit/miss/deny.
#[derive(Debug)]
pub enum TeleportVerdict {
    /// Validated + frozen volume hit: serve the geodesicLength:0 replay.
    Admitted {
        tail_residual: Vec<f32>,
        kv_slab: Vec<f32>,
    },
    /// Validated but no frozen volume: run the heavy path.
    Miss,
    /// Projection drift: fail-closed, no replay.
    Denied { reason: String },
}

/// Validate the protocol69 envelope, then replay the amplituhedron volume keyed
/// by `(prefix_hash, prefix_len, layer_lo, layer_hi)`. Fail-closed on drift.
pub fn teleport_admit(
    envelope: &Protocol69ProjectionEnvelope,
    cache: &mut AmplituhedronCache,
    prefix_hash: u64,
    prefix_len: u32,
    layer_lo: u16,
    layer_hi: u16,
) -> TeleportAdmission {
    match validate_protocol69_projection_envelope(envelope) {
        Err(reason) => TeleportAdmission {
            protocol69_valid: false,
            cache_hit: false,
            geodesic_length: TELEPORT_GEODESIC_LENGTH,
            hit_payload: None,
            denial_reason: Some(reason),
        },
        Ok(()) => {
            let hit = cache.replay(prefix_hash, prefix_len, layer_lo, layer_hi);
            TeleportAdmission {
                protocol69_valid: true,
                cache_hit: hit.is_some(),
                geodesic_length: TELEPORT_GEODESIC_LENGTH,
                hit_payload: hit,
                denial_reason: None,
            }
        }
    }
}

/// Canonical key mapping used across the mesh: `broadcast_symbol -> prefix_hash`,
/// `local_foil_operand -> prefix_len`, layers `[0, 1)`. Matches the rf-cache-key
/// replayContract (prefixHash 66, prefixLen 7).
pub fn teleport_admit_canonical(
    envelope: &Protocol69ProjectionEnvelope,
    cache: &mut AmplituhedronCache,
) -> TeleportAdmission {
    teleport_admit(
        envelope,
        cache,
        envelope.broadcast_symbol as u64,
        envelope.local_foil_operand,
        0,
        1,
    )
}

/// Collapse an admission into the three-way verdict.
pub fn verdict(admission: TeleportAdmission) -> TeleportVerdict {
    if let Some(reason) = admission.denial_reason {
        return TeleportVerdict::Denied { reason };
    }
    match admission.hit_payload {
        Some((tail_residual, kv_slab)) => TeleportVerdict::Admitted {
            tail_residual,
            kv_slab,
        },
        None => TeleportVerdict::Miss,
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::protocol69::build_protocol69_projection_envelope;

    #[test]
    fn canonical_hit_is_geodesic_zero() {
        let mut cache = AmplituhedronCache::new();
        cache.capture(66, 7, 0, 1, vec![1.0; 8], vec![2.0; 64]);
        let env = build_protocol69_projection_envelope();
        let a = teleport_admit_canonical(&env, &mut cache);
        assert!(a.protocol69_valid);
        assert!(a.cache_hit);
        assert_eq!(a.geodesic_length, 0);
        let (tail, kv) = a.hit_payload.expect("hit");
        assert_eq!(tail.len(), 8);
        assert_eq!(kv.len(), 64);
    }

    #[test]
    fn drift_is_denied_no_replay() {
        let mut cache = AmplituhedronCache::new();
        cache.capture(66, 7, 0, 1, vec![1.0; 8], vec![2.0; 64]);
        let mut env = build_protocol69_projection_envelope();
        env.expected_projection = 68; // drift
        let a = teleport_admit_canonical(&env, &mut cache);
        assert!(!a.protocol69_valid);
        assert!(!a.cache_hit);
        assert!(a.denial_reason.is_some());
        assert!(matches!(verdict(a), TeleportVerdict::Denied { .. }));
    }

    #[test]
    fn valid_but_empty_cache_is_miss() {
        let mut cache = AmplituhedronCache::new();
        let env = build_protocol69_projection_envelope();
        let a = teleport_admit_canonical(&env, &mut cache);
        assert!(a.protocol69_valid);
        assert!(!a.cache_hit);
        assert!(matches!(verdict(a), TeleportVerdict::Miss));
    }
}
